#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, P;
        scanf("%d %d", &N, &P);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int max_score = 0;
        int count = 0;
        for (int i = 0; i < N; i++) {
            int sum = 0;
            for (int j = i; j < N; j++) {
                sum = (sum + A[j]) % P;
                if (sum > max_score) {
                    max_score = sum;
                    count = 1;
                } else if (sum == max_score) {
                    count++;
                }
            }
        }
        printf("%d %d\n", max_score, count);
    }
    return 0;
}

