import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int P = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int max_score = 0;
            int count = 0;
            for (int i = 0; i < N; i++) {
                int sum = 0;
                for (int j = i; j < N; j++) {
                    sum = (sum + A[j]) % P;
                    if (sum > max_score) {
                        max_score = sum;
                        count = 1;
                    } else if (sum == max_score) {
                        count++;
                    }
                }
            }
            System.out.println(max_score + " " + count);
        }
    }
}

